BEGIN;

-- Reset APP scope bookmarks/tags.
DELETE FROM "bookmark_tags" bt
USING "bookmarks" b
WHERE bt."bookmark_id" = b."id"
  AND b."scope" = 'APP';

DELETE FROM "bookmark_tags" bt
USING "tags" t
WHERE bt."tag_id" = t."id"
