WITH recount AS (
  SELECT
    t."id" AS "tag_id",
    COUNT(bt."bookmark_id")::int AS "cnt"
  FROM "tags" t
  LEFT JOIN "bookmark_tags" bt ON bt."tag_id" = t."id"
  WHERE t."scope" = 'APP'
  GROUP BY t."id"
)
UPDATE "tags" t
SET "bookmark_count" = recount."cnt", "updated_at" = NOW()
FROM recount
WHERE t."id" = recount."tag_id";

COMMIT;
